<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller; use App\Http\Requests\Admin\TravelRouteRequest; use App\Models\{Location,TravelRoute}; use App\Services\Admin\RouteService;
class TravelRouteController extends Controller { public function index(){ $this->authorize('manage',TravelRoute::class); return view('admin.travel-routes.index',['routes'=>TravelRoute::with('origin','destination')->latest()->paginate(15)]); } public function create(){ $this->authorize('manage',TravelRoute::class); return view('admin.travel-routes.form',['route'=>null,'locations'=>Location::where('status','active')->get()]); } public function store(TravelRouteRequest $r, RouteService $s){ $s->save($r->validated()); return redirect()->route('admin.travel-routes.index'); } public function edit(TravelRoute $travel_route){ $this->authorize('manage',TravelRoute::class); $travel_route->load('stops','charges'); return view('admin.travel-routes.form',['route'=>$travel_route,'locations'=>Location::where('status','active')->get()]); } public function update(TravelRouteRequest $r, TravelRoute $travel_route, RouteService $s){ $s->save($r->validated(),$travel_route); return redirect()->route('admin.travel-routes.index'); } public function destroy(TravelRoute $travel_route){ $this->authorize('manage',TravelRoute::class); $travel_route->delete(); return back(); } }
